import{j as e}from"./vendor-Dh_dlHsl.js";import{C as t,A as s,N as a,E as i,P as n,W as o}from"./subject-01-thinking-in-agents-BIrOrpH9.js";const v={id:"workflows",title:"Reusable Workflows",description:"Packaging agent expertise into repeatable, shareable patterns — skills, automation, and scheduled execution.",icon:"🔄",colorHex:"#ca8a04",difficulty:"intermediate",estimatedHours:8,prerequisites:["tools","prompt-engineering"],chapters:[{id:"c1-skill-concept",title:"The Skill Concept",description:"What skills are and why packaging workflows matters.",difficulty:"intermediate",estimatedMinutes:80,sections:[{id:"s1-what-is-skill",title:"What Is a Skill",description:"Bundled knowledge, tools, and workflow — reusable agent expertise.",difficulty:"intermediate",readingMinutes:10},{id:"s2-identifying-patterns",title:"Identifying Patterns Worth Packaging",description:"When a workflow is repeated enough to deserve its own name and structure.",difficulty:"intermediate",readingMinutes:10},{id:"s3-builtin-vs-custom",title:"Built-In vs Custom Skills",description:"What comes out of the box vs what you build for your specific domain.",difficulty:"intermediate",readingMinutes:10},{id:"s4-skill-invocation",title:"Skill Invocation",description:"Making complex workflows feel simple — slash commands and natural language triggers.",difficulty:"intermediate",readingMinutes:10}]},{id:"c2-designing-skills",title:"Designing Skills",description:"How to create effective, composable, parameterized skills.",difficulty:"intermediate",estimatedMinutes:80,sections:[{id:"s1-parameterized-templates",title:"Parameterized Templates",description:"Skills that adapt to input — flexible prompts with variable slots.",difficulty:"intermediate",readingMinutes:10},{id:"s2-tool-requirements",title:"Tool Requirements",description:"What a skill needs to function — declaring tool dependencies upfront.",difficulty:"intermediate",readingMinutes:10},{id:"s3-composing-skills",title:"Composing Skills",description:"Building complex workflows from simple ones — skill chains and nesting.",difficulty:"advanced",readingMinutes:12},{id:"s4-domain-skills",title:"Skills for Common Domains",description:"Debugging, reviewing, refactoring — skills that every developer agent needs.",difficulty:"intermediate",readingMinutes:10}]},{id:"c3-automation",title:"Automation and Scheduling",description:"Agents that run on timers, respond to events, and integrate into pipelines.",difficulty:"advanced",estimatedMinutes:80,sections:[{id:"s1-scheduled-agents",title:"Scheduled Agents",description:"Running on a timer — cron-based recurring agent execution.",difficulty:"intermediate",readingMinutes:10},{id:"s2-event-driven",title:"Event-Driven Agents",description:"Responding to external triggers — webhooks, PR events, and system signals.",difficulty:"advanced",readingMinutes:12},{id:"s3-hook-automation",title:"Hook-Based Automation",description:"Pre and post action callbacks — running logic before or after agent actions.",difficulty:"advanced",readingMinutes:12},{id:"s4-ci-agents",title:"Agents in Continuous Integration",description:"Automating development workflows — agents as CI pipeline participants.",difficulty:"advanced",readingMinutes:10}]}]};function r(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"What Is a Skill?"}),e.jsx("p",{children:"As agents take on more complex work, a pattern emerges: certain multi-step tasks are performed repeatedly, with slight variations but the same underlying structure. Rather than rediscovering how to do them each time, we can package that know-how into a reusable unit. This is the concept of a skill — a named, reusable pattern for accomplishing a specific type of task."}),e.jsx(t,{title:"Skill",number:"10.1",children:e.jsx("p",{children:"A skill is a reusable, named unit of agent behavior that encapsulates a repeatable task pattern — including the steps to perform, the tools required, and the decisions to make along the way. Skills turn recurring multi-step tasks into single invocable units, reducing repetition and ensuring consistent execution across all instances of that task type."})}),e.jsx("p",{children:"Skills sit above individual tool calls but below full agent systems in the hierarchy of abstraction. A single tool call is the most granular unit of action. A skill combines several tool calls and decision points into a coherent procedure. An agent is a system that can reason about when and how to invoke skills. This layering makes complex agents easier to build, test, and reason about."}),e.jsx(s,{title:"A Recipe",children:e.jsx("p",{children:"A recipe is a skill for cooking a dish. It names the dish (what you are making), lists the ingredients (resources required), specifies the steps (the procedure), and describes what done looks like (the success condition). You do not re-derive the recipe every time you cook — you follow it, possibly with variations for what is in the pantry. Agent skills work the same way: they capture proven procedures so they can be reused without reinvention."})}),e.jsx(a,{title:"Skills are not code functions",type:"note",children:e.jsx("p",{children:"Unlike code functions, skills involve judgment at multiple points: which tool to use when several are available, how to handle a partial result, when to stop and ask for clarification. A skill is more like a professional procedure than a deterministic algorithm — it provides structure while leaving room for the agent to adapt to circumstances."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex10-1-1",difficulty:"beginner",question:'Is "search the web" a skill? What about "research a topic and produce a summary"? Explain the distinction.',hint:"Consider how many steps and decisions each involves, and whether the procedure is well enough defined to be reused.",solution:'"Search the web" is a single tool call, not a skill — it is one atomic action with one input and one output. "Research a topic and produce a summary" is a skill: it involves multiple steps (formulate queries, search, evaluate results, synthesize, format), decision points (is this source credible? do I need more results?), and a defined output shape. The difference is complexity, sequencing, and the presence of decision points that must be resolved during execution.'},{id:"ex10-1-2",difficulty:"intermediate",question:"An agent performs the following sequence repeatedly: check if a file exists, read it if it does, transform its contents, and save it to a new location. At what point should this be extracted into a named skill, and what are the benefits of doing so?",hint:"Think about when repetition and variation signal that a skill is warranted.",solution:"The sequence should be extracted into a skill once it has been repeated more than a few times with consistent structure. Benefits: (1) Consistency — every execution follows the same procedure, reducing the chance of the agent improvising a different sequence. (2) Testability — the skill can be tested in isolation against known inputs and outputs. (3) Reuse — the agent can invoke the skill by name without re-specifying all the steps. (4) Documentation — a named skill communicates intent; unnamed ad hoc step sequences obscure it. The signal that extraction is warranted is repetition with variation: the same structure applied to different files."},{id:"ex10-1-3",difficulty:"advanced",question:"Skills add abstraction, but abstraction has costs. What are the downsides of over-skill-ing an agent system, and how would you decide the right level of granularity for skills in a given domain?",hint:"Consider what you lose when a procedure is encapsulated: visibility, flexibility, and the ability to handle edge cases that the skill definition did not anticipate.",solution:'Downsides of over-skill-ing: (1) Rigidity — a well-encapsulated skill hides its steps, making it harder to adjust when an edge case requires a deviation from the standard procedure. (2) Abstraction mismatch — skills defined at the wrong granularity force agents to either call multiple fine-grained skills in an ad hoc sequence (defeating the purpose) or use a coarse skill that does too much. (3) Maintenance overhead — more named skills means more definitions to keep updated. Right granularity: define skills at the level of complete, meaningful outcomes — things a user or operator would recognize as a unit of work. "Send a status report" is a good skill boundary; "format a paragraph" is too fine. When in doubt, start with fewer, larger skills and decompose them only when variation across instances requires it.'}]})]})}const x=Object.freeze(Object.defineProperty({__proto__:null,default:r},Symbol.toStringTag,{value:"Module"}));function l(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Identifying Skill Patterns"}),e.jsx("p",{children:"Skills do not appear fully formed — they are discovered by noticing patterns in agent behavior. When the same sequence of steps, the same decision structure, or the same type of output appears across multiple tasks, that repetition is a signal that a skill is waiting to be named and extracted. The discipline of identifying patterns is what separates an agent with ad hoc behavior from one with a coherent capability vocabulary."}),e.jsx(t,{title:"Skill Pattern",number:"10.2",children:e.jsx("p",{children:"A skill pattern is a recurring structure in agent behavior: a set of steps that appear together consistently, applied to varying inputs but producing a consistent type of output. Identifying a skill pattern means recognizing when something an agent already does repeatedly has enough structure and consistency to be made explicit, named, and reused."})}),e.jsxs("p",{children:["Four signals indicate that a pattern has emerged and a skill should be extracted. First, ",e.jsx("strong",{children:"repetition"}),": the same sequence of steps appears in multiple tasks. Second, ",e.jsx("strong",{children:"variation in inputs but consistency in structure"}),": the steps are the same, but they operate on different data each time. Third, ",e.jsx("strong",{children:"a clear output type"}),": the procedure reliably produces a recognizable kind of result. Fourth,",e.jsx("strong",{children:" transferability"}),": the procedure would be useful in contexts other than the one where it first appeared."]}),e.jsx(s,{title:"The Surgeon's Checklists",children:e.jsx("p",{children:"Surgeons use pre-operative checklists not because they forget how to operate, but because they noticed that certain mistakes recurred under pressure — and that a structured procedure eliminated them. The checklist captures a pattern that proved its value through repetition. Identifying agent skill patterns works the same way: watch for what works, notice its structure, and formalize it."})}),e.jsx(n,{title:"Name What You Can Repeat",number:"10.1",children:e.jsx("p",{children:"If you find yourself describing the same sequence of steps when explaining what an agent should do, that description wants to become a skill. The act of naming a pattern makes it possible to reason about it, test it, and improve it independently. Unnamed patterns are invisible; named patterns are manageable."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex10-2-1",difficulty:"beginner",question:"An agent has been observed doing the following in different tasks: (a) finding a customer's recent orders and summarizing them; (b) finding a product's recent reviews and summarizing them; (c) finding a support ticket's recent updates and summarizing them. What common skill pattern do these share, and what should the skill be named?",hint:"Ignore the specific domain (customer, product, ticket) and look at the structural similarity.",solution:'The common pattern is: retrieve recent items for a given entity, then summarize them. This is a "Recent Activity Summary" skill (or similar). The skill takes an entity type and entity identifier as parameters, retrieves recent related items, and produces a structured summary. The specific domains (customer, product, support ticket) are instances of the same pattern — they differ only in which tool is called during the retrieval step, which can be parameterized.'},{id:"ex10-2-2",difficulty:"intermediate",question:"How would you systematically analyze an agent's execution history to identify skill candidates? Describe a process for surfacing patterns from a log of past agent runs.",hint:"Think about what you would look for in the logs: repeated sequences, common output shapes, clustered tool combinations.",solution:"Process: (1) Collect execution traces — the sequence of tool calls, decisions, and outputs for a sample of completed tasks. (2) Normalize the traces by removing task-specific values (keep the structure, replace the data with placeholders). (3) Cluster normalized traces by structural similarity — sequences that look the same after normalization are candidates for a shared skill. (4) Identify clusters with the following properties: appear in at least 3-5 tasks, have a consistent output shape, and cover the full sequence from a recognizable starting condition to a recognizable completion. (5) Review the top clusters with a domain expert to confirm they represent meaningful units of work. The result is a ranked list of skill candidates with evidence from actual execution history."},{id:"ex10-2-3",difficulty:"advanced",question:"Not all recurring patterns should become skills. Describe two types of recurring patterns that should NOT be extracted into skills, and explain why.",hint:"Consider patterns that are too context-specific, too unstable, or where the variation between instances is the important part.",solution:'Type 1: Highly context-specific one-offs disguised as patterns. Some tasks appear structurally similar but their variations are not incidental — they reflect genuinely different requirements. Extracting them into a skill forces all instances into the same mold, obscuring important differences. Example: "handle a customer escalation" may look similar across instances but the right response varies so much by context that a fixed procedure is actually harmful. Type 2: Unstable patterns in rapidly changing domains. If the steps in a pattern change frequently because the underlying domain or tools are evolving, extracting it into a skill creates a skill that is constantly out of date. The overhead of maintaining the skill exceeds the benefit of having it. The signal: if you would need to update the skill definition after every few uses, it is not stable enough to be a skill yet.'}]})]})}const j=Object.freeze(Object.defineProperty({__proto__:null,default:l},Symbol.toStringTag,{value:"Module"}));function c(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Built-in vs. Custom Skills"}),e.jsx("p",{children:"Some skills come with an agent platform — general-purpose capabilities like web search, code execution, or document retrieval that apply across many domains. Others must be built for a specific organization, process, or dataset. Understanding the difference between built-in and custom skills, and knowing when each is appropriate, is a foundational skill design decision."}),e.jsx(t,{title:"Built-in Skills",number:"10.3",children:e.jsx("p",{children:"Built-in skills are general-purpose capabilities provided by the agent platform that work across domains without customization. They handle common patterns — searching, summarizing, executing computations — that appear in many different workflows. Built-in skills are immediately available, well-tested, and maintained by the platform. They are the right starting point before building anything custom."})}),e.jsx(t,{title:"Custom Skills",number:"10.4",children:e.jsx("p",{children:"Custom skills encode domain-specific procedures, organizational conventions, or proprietary data access patterns that no general platform can anticipate. They are built by the team deploying the agent and reflect deep knowledge of a specific context. Custom skills are necessary when the task requires judgment, data access, or procedures that are unique to the organization."})}),e.jsx(a,{title:"Prefer built-in before custom",type:"tip",children:e.jsx("p",{children:"Every custom skill is an ongoing maintenance commitment. Before building a custom skill, check whether a built-in skill handles 80% of the use case. Adapting the task to fit a built-in skill is often faster and more reliable than building a purpose-specific custom one. Build custom only when the fit is genuinely poor."})}),e.jsx(o,{title:"Custom skills become stale",children:e.jsx("p",{children:"Unlike built-in skills maintained by a platform team, custom skills are maintained by the team that built them. When the underlying process, data schema, or tool changes, the custom skill must be updated. Teams that build many custom skills without a maintenance plan find themselves with a growing inventory of skills that no longer work as described."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ex10-3-1",difficulty:"beginner",question:"A team wants to build an agent that answers questions about company policy documents. Should they build a custom skill for this, or can a built-in skill handle it? What factors determine the answer?",hint:"Consider whether the task requires access to proprietary content, specialized retrieval logic, or just general document Q&A behavior.",solution:'It depends on the retrieval and access requirements. If the policy documents are accessible as public files and the questions are straightforward factual queries, a built-in document Q&A skill may handle it. If the documents are stored in a proprietary internal system, require specific access credentials, are structured in a non-standard format, or if the "correct" answers reflect organizational interpretations rather than literal text, a custom skill is warranted. The deciding factors are: data access (proprietary vs. accessible), content complexity (standard vs. specialized), and answer expectations (literal retrieval vs. interpreted). Most enterprise policy Q&A systems require at least some custom work.'},{id:"ex10-3-2",difficulty:"intermediate",question:"A built-in summarization skill produces summaries in a generic format. The organization needs summaries in their specific template: three bullet points, a risk flag, and a recommended next action. Should they modify the built-in skill or build a custom one? What are the tradeoffs?",hint:'Consider whether the platform allows configuration of built-in skills, or whether "modification" means building on top of the built-in.',solution:'If the platform allows configuration of output format (e.g., a template parameter), configure the built-in skill — this is the lowest effort path. If configuration is not available, the right approach is to wrap the built-in skill in a thin custom layer: call the built-in summarization skill, then pass its output through a formatting step that produces the required structure. This is not "modifying" the built-in but composing with it. Building a fully custom summarization skill from scratch wastes effort and loses the quality improvements the platform team applies to the built-in. The principle is: reuse the expensive part (the summarization intelligence), customize only the cheap part (the output format).'},{id:"ex10-3-3",difficulty:"advanced",question:"Design a decision framework for when to build a custom skill versus adapting a built-in. Your framework should consider at least four dimensions and produce a clear recommendation.",hint:"Think about data access, task specificity, maintenance cost, and the quality gap between built-in and custom.",solution:"Four-dimension framework: (1) Data access: does the task require proprietary, internal, or non-public data? If yes, custom skill required — built-ins cannot access data they are not given. (2) Process specificity: does the task encode organizational conventions, legal requirements, or institutional judgment that differs from general best practice? If yes, custom. (3) Quality gap: if you tried a built-in skill, how close was the output to what is needed? If within minor formatting adjustments, prefer built-in + wrapper. If fundamentally different in substance, custom. (4) Maintenance capacity: does the team have ongoing capacity to maintain the skill as the underlying data, process, or tools evolve? If no, prefer a simpler built-in solution even if it is a worse fit. Recommendation rule: use custom only if at least two of these dimensions require it AND maintenance capacity exists. Otherwise, adapt to built-in."}]})]})}const T=Object.freeze(Object.defineProperty({__proto__:null,default:c},Symbol.toStringTag,{value:"Module"}));function h(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Skill Invocation"}),e.jsx("p",{children:"A skill that exists but cannot be easily triggered is a skill that will not be used. Invocation is the bridge between a user's intent and the execution of a complex workflow. The quality of the invocation interface determines whether a skill feels like a natural extension of conversation or an obscure command that requires a manual."}),e.jsx(t,{title:"Skill Invocation",number:"10.4",children:e.jsx("p",{children:"Skill invocation is the mechanism by which a user or system triggers execution of a skill. Invocation methods range from explicit (slash commands like /review or /deploy) to implicit (the agent recognizes from natural language that a skill is relevant and invokes it automatically). The invocation layer is responsible for parsing the trigger, extracting parameters, validating that preconditions are met, and initiating execution."})}),e.jsx(s,{title:"The Restaurant Order",children:e.jsx("p",{children:'At a restaurant, you can order by pointing at the menu and saying "number 7" (explicit invocation) or by describing what you want — "something light, no gluten, with vegetables" — and letting the waiter recommend a dish (implicit invocation). Both get you food, but they require different levels of knowledge from the customer and different levels of interpretation from the waiter. Skill invocation works the same way: some users want the precision of a command, others want the flexibility of a description.'})}),e.jsx("p",{children:"The best invocation systems support both modes. Power users who know exactly what they want use slash commands for speed and precision. New users who know what they need but not what it is called describe their goal, and the agent matches it to the right skill. Supporting both modes requires the skill to have rich metadata — not just a name, but a description of what it does and when it is appropriate."}),e.jsx(n,{title:"Invocation Should Match User Intent, Not System Structure",number:"10.2",children:e.jsx("p",{children:`Users think in terms of goals: "review this PR," "set up the database," "check for security issues." They do not think in terms of skill registries or workflow graphs. The invocation interface should accept goal-oriented language and map it to the correct skill, even if the skill's internal name is technical. When invocation requires users to learn the system's vocabulary, adoption drops.`})}),e.jsx(a,{title:"Disambiguation is part of invocation",type:"note",children:e.jsx("p",{children:`When a user's request could match multiple skills, the agent must disambiguate — either by asking a clarifying question or by using context to select the most likely match. Silent disambiguation (picking one without telling the user) is risky because a wrong guess wastes the user's time. Transparent disambiguation ("I found two skills that match — did you mean X or Y?") builds trust.`})}),e.jsx(i,{title:"Exercises",exercises:[{id:"si-1",difficulty:"beginner",question:'A developer types "check my code for problems" to an agent that has skills for linting, security scanning, and test coverage analysis. How should the agent decide which skill to invoke? What if the answer is "all of them"?',hint:"Consider whether the request is ambiguous or whether it implies a broad intent that multiple skills serve.",solution:'The request "check my code for problems" is broad enough to encompass all three skills. The agent should recognize this as a composite intent and either: (a) invoke all three in sequence, presenting results from each, or (b) ask "I can check for lint issues, security vulnerabilities, and test coverage gaps — would you like all three or a specific one?" Option (a) is better for experienced users who expect comprehensive results. Option (b) is better when resources are limited or the user might want a quick check rather than a full analysis. The agent should use context (e.g., is this a quick chat or a pre-commit review?) to decide which approach to take.'},{id:"si-2",difficulty:"intermediate",question:"Design the metadata schema for a skill that enables both slash command invocation and natural language matching. What fields are required, and how would a matching algorithm use them?",hint:"Think about what a text similarity search needs versus what a command parser needs.",solution:'Required metadata fields: (1) name: the slash command identifier (e.g., "review-pr"), (2) aliases: alternative slash commands (e.g., "pr-review", "code-review"), (3) description: a natural language sentence explaining what the skill does, (4) trigger_phrases: example natural language requests that should activate this skill (e.g., "review this pull request", "check my PR", "look at these changes"), (5) parameters: the inputs the skill accepts with types and descriptions, (6) preconditions: what must be true for this skill to be applicable (e.g., "must be in a git repository with an open PR"). A matching algorithm uses name and aliases for exact slash command matching, and uses description and trigger_phrases for semantic similarity matching against natural language input. Preconditions are checked after matching to confirm the skill is applicable in the current context.'}]})]})}const q=Object.freeze(Object.defineProperty({__proto__:null,default:h},Symbol.toStringTag,{value:"Module"}));function d(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Parameterized Templates"}),e.jsx("p",{children:"A skill that works for exactly one situation is not reusable — it is a script. True reusability comes from parameterization: designing skills with variable slots that adapt their behavior to the specific context they are invoked in. Parameters transform a rigid procedure into a flexible template."}),e.jsx(t,{title:"Parameterized Template",number:"10.5",children:e.jsx("p",{children:"A parameterized template is a skill definition that contains variable slots — placeholders for values that are filled in at invocation time. Parameters might include the target file, the review standard to apply, the output format, or the severity threshold. The template defines the structure of the workflow; the parameters customize it for a specific use. Well-parameterized skills are written once and used in many contexts."})}),e.jsx(s,{title:"The Mad Libs Approach",children:e.jsx("p",{children:'A Mad Libs game has a fixed story structure with blanks for nouns, verbs, and adjectives. The structure stays the same, but filling in different words produces wildly different stories. A parameterized skill template works the same way: the workflow logic is the fixed structure, and the parameters are the blanks. "Review [file] for [standard] and report issues above [severity]" is one template that handles hundreds of specific review scenarios.'})}),e.jsx("p",{children:"The art of parameterization is choosing the right level of abstraction. Too few parameters and the skill is rigid — it works only in narrow conditions. Too many parameters and the skill becomes confusing — users must specify so many values that invoking the skill is as complex as doing the task manually."}),e.jsx(n,{title:"Parameterize the What, Not the How",number:"10.3",children:e.jsx("p",{children:"Parameters should let users specify what they want done, not how to do it. Good parameters: target file, output format, quality standard. Bad parameters: which internal step to skip, what prompt to use at step three, how many retries to attempt. When parameters expose internal mechanics, the skill's implementation cannot change without breaking every caller. Keep the interface about intent and the implementation about execution."})}),e.jsx(o,{title:"Unvalidated parameters cause silent failures",children:e.jsx("p",{children:'A parameter that accepts any value without validation is a trap. If a severity threshold expects a number between 1 and 5 but receives "high," the skill may silently produce wrong results rather than failing clearly. Every parameter needs a type, a validation rule, and a clear error message when the value is invalid. Fail loudly at invocation time rather than silently during execution.'})}),e.jsx(i,{title:"Exercises",exercises:[{id:"pt-1",difficulty:"beginner",question:"A team has a skill that reviews Python files for PEP 8 compliance. They want to reuse it for JavaScript files with ESLint rules. What parameters would make this a single, reusable skill instead of two separate ones?",hint:"Identify what differs between the two use cases and make those the parameters.",solution:'The reusable skill needs at minimum three parameters: (1) target_language — "python" or "javascript" — which determines the file types to scan, (2) style_standard — "pep8" or "eslint" — which determines the rules to apply, and (3) target_path — the file or directory to review. The workflow structure (scan files, apply rules, report violations) is identical; only the inputs change. Optionally, a severity_filter parameter lets users control whether to see all issues or only errors. This single parameterized skill replaces two hard-coded ones and can extend to any language by adding new standard options.'},{id:"pt-2",difficulty:"intermediate",question:"A skill template has 12 parameters. Users complain it is too complex to use. How do you reduce the cognitive load without removing flexibility?",hint:"Think about which parameters most users leave at their default value.",solution:'Apply a layered parameter strategy. (1) Identify the 2-3 parameters that vary in every invocation (e.g., target file, output format) — these are required. (2) Set sensible defaults for the remaining 9-10 parameters based on the most common use case. (3) Group the optional parameters into logical categories (e.g., "formatting options," "filter options") so that users who need them can find them, but users who do not can ignore them. The result: most invocations specify only 2-3 values, power users can override any default, and the skill retains full flexibility. The key insight is that good defaults are a form of design — they encode your understanding of the most common use case.'},{id:"pt-3",difficulty:"advanced",question:"Design a parameter inference system where the skill automatically determines parameter values from context when the user does not provide them. What context sources would you use, what are the risks, and how do you handle uncertainty?",hint:"Think about what the current environment, recent conversation, and file system can tell you about likely parameter values.",solution:`Context sources for inference: (1) Current working directory and file types present — infer target_language. (2) Project configuration files (e.g., linter configs) — infer style_standard. (3) Recent conversation history — infer intent and scope. (4) Git status — infer which files were recently changed and are likely targets. Risks: (a) incorrect inference leads to the skill operating on wrong files or with wrong settings, (b) users may not realize values were inferred and may not check them. Mitigation: always display inferred values before execution ("I'll review src/main.py using PEP 8 — proceed?"). Allow users to correct any inference. Never infer destructive parameters (e.g., "delete after review") — require those explicitly. Treat inference as a suggestion, not a decision.`}]})]})}const A=Object.freeze(Object.defineProperty({__proto__:null,default:d},Symbol.toStringTag,{value:"Module"}));function u(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Tool Requirements"}),e.jsx("p",{children:"A skill is only as capable as the tools available to it. A code review skill without file reading tools cannot review code. A deployment skill without access to the target environment cannot deploy. Declaring tool requirements upfront is how a skill communicates what it needs to function — and how the system verifies those needs are met before execution begins."}),e.jsx(t,{title:"Tool Requirements",number:"10.6",children:e.jsx("p",{children:"Tool requirements are the explicit declaration of which tools a skill depends on to perform its work. A requirement specifies not just the tool name but the capabilities needed — read access versus write access, which endpoints or resources, and what permissions. Declaring requirements serves two purposes: it enables the runtime to verify availability before execution starts, and it documents the skill's capabilities and limitations for anyone evaluating whether to use it."})}),e.jsx(s,{title:"The Recipe's Ingredient List",children:e.jsx("p",{children:"A recipe lists ingredients before the instructions begin. This lets the cook check the pantry before starting — far better than discovering halfway through that a critical ingredient is missing. Tool requirements serve the same purpose for skills. They let the system check that everything is available before the skill starts running, avoiding partial execution that wastes time and may leave things in a broken state."})}),e.jsx("p",{children:"Requirements should be declared at different levels of necessity. Some tools are essential — without them the skill cannot run at all. Others are optional — the skill can produce a reduced result without them. And some are conditional — needed only when certain parameters are set. This granularity prevents skills from being blocked by the absence of tools they would not have used anyway."}),e.jsx(n,{title:"Fail Before Starting, Not During Execution",number:"10.4",children:e.jsx("p",{children:"A skill that starts running and then fails because a required tool is missing has wasted time and possibly created side effects that must be cleaned up. Checking tool requirements before execution is a pre-flight check. It is always cheaper to discover a missing dependency before work begins than after work is partially complete."})}),e.jsx(a,{title:"Permissions are part of requirements",type:"note",children:e.jsx("p",{children:"A tool being present is not sufficient — the skill also needs appropriate permissions. A file system tool that exists but lacks write permission will cause a skill that needs to create files to fail mid-execution. Tool requirements should specify the permission level needed, not just the tool name. Pre-flight checks should verify both presence and access."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"tr-1",difficulty:"beginner",question:'A skill called "generate-changelog" reads git history, formats a changelog, and writes it to a file. What are its tool requirements? Classify each as essential, optional, or conditional.',hint:"Walk through each step of the skill and identify what tool it needs.",solution:'Essential: (1) Git history access — without it, the skill has no data to work from. (2) File write access — the final changelog must be written somewhere. Optional: (3) Issue tracker access — if available, the skill can enrich changelog entries with ticket numbers and descriptions; without it, the changelog is still useful but less detailed. Conditional: (4) Notification tool — needed only if the "notify_team" parameter is set to true. The skill should declare all four, categorized by necessity, so the runtime knows which missing tools are blockers and which are graceful degradations.'},{id:"tr-2",difficulty:"intermediate",question:'A skill declares it requires a "database" tool but two different database tools are available — one for PostgreSQL and one for MongoDB. How should the requirement system handle this? What additional information should requirements specify?',hint:'Think about whether "database" is specific enough as a requirement, and what happens when multiple tools match a generic requirement.',solution:'The requirement "database" is too vague. Requirements should specify capability types rather than generic categories: "relational-database-query" or "document-store-read" rather than "database." When a skill declares a capability requirement, the runtime matches it against tools that advertise that capability. If multiple tools match, the resolution strategy should be: (1) check if the skill specifies a preference order, (2) check if the project configuration designates a default for that capability, (3) ask the user which to use. The requirement schema should include: capability type, minimum required operations (read, write, schema-modify), and optionally a preferred tool name for environments where the choice is known.'}]})]})}const S=Object.freeze(Object.defineProperty({__proto__:null,default:u},Symbol.toStringTag,{value:"Module"}));function p(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Composing Skills"}),e.jsx("p",{children:"Simple skills handle single tasks well. But real workflows are multi-step: analyze, then transform, then validate, then report. Rather than building monolithic skills that handle every step, the more powerful approach is to compose simple skills into complex workflows — letting each skill do one thing well and chaining them together."}),e.jsx(t,{title:"Skill Composition",number:"10.7",children:e.jsx("p",{children:"Skill composition is the practice of building complex workflows by connecting simpler skills in sequence, in parallel, or in conditional branches. A composed workflow defines the order of execution, how data flows from one skill's output to the next skill's input, and what happens when an intermediate skill fails. Composition turns a library of small, focused skills into a system capable of handling sophisticated multi-step processes."})}),e.jsx(s,{title:"Assembly Line Manufacturing",children:e.jsx("p",{children:"A car factory does not have one enormous machine that takes in raw steel and produces a finished car. It has stations: one stamps body panels, another welds the frame, another installs the engine, another paints. Each station does one thing expertly. The assembly line composes these stations into a complete manufacturing process. Skill composition works the same way — each skill is a station, and the composition defines the line."})}),e.jsx("p",{children:"The critical challenge in composition is the interface between skills. The output of one skill must be compatible with the input of the next. When skills are designed independently, these interfaces often mismatch — one produces a summary as free text while the next expects structured data. Successful composition requires deliberate interface design."}),e.jsx(n,{title:"Design Skills for Composition, Not Just Standalone Use",number:"10.5",children:e.jsx("p",{children:'A skill designed only for direct user invocation often produces human-readable output that is difficult for another skill to parse. Skills designed for composition produce structured, predictable output that both humans and downstream skills can consume. When building a skill, ask: "Could another skill use my output as its input?" If the answer is no, the skill is a dead end in any composed workflow.'})}),e.jsx(o,{title:"Deep composition chains amplify failures",children:e.jsx("p",{children:"A chain of ten skills where each depends on the previous one has ten points of failure. If any skill fails, everything downstream is blocked. Worse, errors can propagate subtly — a slightly wrong output from skill three may not cause skill four to fail, but may cause skill seven to produce nonsense. Keep composition chains as short as practical, and validate intermediate results at key checkpoints."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"cs-1",difficulty:"beginner",question:'You have three skills: "gather-requirements" (outputs a list of requirements), "generate-tests" (takes requirements, outputs test descriptions), and "estimate-effort" (takes test descriptions, outputs time estimates). How would you compose them into a single workflow? What data flows between each step?',hint:"Trace the output of each skill and how it becomes the input of the next.",solution:"The composition is a linear chain: gather-requirements → generate-tests → estimate-effort. Data flow: (1) gather-requirements produces a structured list of requirements (each with an ID, description, and priority). (2) generate-tests consumes this list and produces a list of test descriptions (each linked to a requirement ID). (3) estimate-effort consumes the test descriptions and produces time estimates per test. The final output is a report mapping requirements → tests → time estimates. The key design requirement is that each skill's output format is exactly what the next skill expects as input — this must be defined in the interface contracts, not left to chance."},{id:"cs-2",difficulty:"intermediate",question:"A composed workflow fails at step 4 of 6. The first three steps completed successfully and produced side effects (files were created, notifications were sent). How should the composition framework handle this partial failure?",hint:'Consider what "rollback" means when some side effects are irreversible, and what information the user needs.',solution:'The framework should: (1) Stop execution immediately — do not attempt steps 5 and 6 with missing input from step 4. (2) Preserve all outputs from steps 1-3 so they are not lost. (3) Record the exact failure point and error from step 4. (4) For reversible side effects (created files), offer rollback. For irreversible side effects (sent notifications), document what was already done so the user can account for it. (5) Enable "resume from step 4" — after the user fixes the issue, the workflow should be able to restart from the failure point using preserved outputs from steps 1-3, without re-executing completed work. Partial failure handling must be designed into the composition framework, not added as an afterthought.'},{id:"cs-3",difficulty:"advanced",question:"Design a composition pattern where two skills run in parallel (both analyzing the same input from different angles) and their outputs are merged by a third skill. What challenges does parallel composition introduce that sequential composition avoids?",hint:"Think about timing, partial failures, and how to merge potentially contradictory outputs.",solution:"Pattern: fan-out/fan-in. The input is sent to both skills simultaneously. A synchronization point waits for both to complete, then passes both outputs to the merge skill. Challenges unique to parallel composition: (1) Timing — one skill may finish in seconds, the other in minutes. The framework must decide whether to wait for both or proceed after a timeout. (2) Partial failure — if one parallel branch fails, should the merge proceed with only one input or should the entire workflow fail? This depends on whether the merge skill can produce useful output from a single input. (3) Contradictory outputs — the two analyses may reach different conclusions. The merge skill must have a resolution strategy (e.g., weighted synthesis, flagging disagreements). (4) Resource contention — if both skills use the same tools or APIs simultaneously, they may interfere with each other. The framework should manage shared resource access across parallel branches."}]})]})}const I=Object.freeze(Object.defineProperty({__proto__:null,default:p},Symbol.toStringTag,{value:"Module"}));function m(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Skills for Common Domains"}),e.jsx("p",{children:"Certain agent tasks appear in nearly every software development context: debugging a failure, reviewing code changes, refactoring for clarity, generating documentation. These recurring patterns are natural candidates for pre-built skills. Understanding what makes a good domain skill — and what pitfalls to avoid — helps teams build skill libraries that deliver consistent value."}),e.jsx(t,{title:"Domain Skill",number:"10.8",children:e.jsx("p",{children:"A domain skill is a reusable workflow designed for a specific, recurring task within a professional domain. In software development, common domain skills include code review, debugging, refactoring, documentation generation, and dependency analysis. A well-designed domain skill encodes expert-level knowledge about how the task should be performed — not just the steps, but the judgment calls, the common pitfalls, and the quality standards that distinguish excellent work from adequate work."})}),e.jsx(s,{title:"The Specialist's Checklist",children:e.jsx("p",{children:"When an experienced surgeon performs an operation, they follow a checklist — not because they have forgotten the steps, but because checklists ensure consistency and catch oversights even when expertise is present. Domain skills serve the same purpose for agent workflows: they encode the expert's checklist so that the quality of execution does not depend on whether the agent happens to remember every consideration. The skill carries the expertise."})}),e.jsx("p",{children:'The most valuable domain skills are those that encode judgment, not just procedure. Any agent can be told to "read the file and list problems." A good code review skill knows to check for security implications, to consider the context of the change relative to the broader system, to distinguish style preferences from genuine issues, and to prioritize feedback by impact.'}),e.jsx(n,{title:"Encode the Expert's Priorities, Not Just Their Steps",number:"10.6",children:e.jsx("p",{children:"The difference between a novice and an expert performing the same task is not the steps they follow — it is what they pay attention to, what they weigh heavily, and what they choose to ignore. A domain skill should capture these priorities explicitly. A debugging skill should encode that reproducing the issue comes before hypothesizing causes. A review skill should encode that correctness matters more than style."})}),e.jsx(a,{title:"Domain skills need domain updates",type:"note",children:e.jsx("p",{children:"Development practices evolve. Security standards change. New patterns emerge and old patterns become anti-patterns. A domain skill that was excellent when written can become misleading if it is not updated as the domain evolves. Build a review cadence into your skill library — revisit domain skills periodically to ensure they reflect current best practices."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ds-1",difficulty:"beginner",question:'List five pieces of expert judgment that a code review domain skill should encode beyond "read the code and find bugs." For each, explain why a generic agent would miss it without the skill.',hint:"Think about what separates a senior developer's code review from a junior developer's.",solution:"(1) Check for security implications — a generic agent may find logic errors but miss that a change exposes user data. (2) Evaluate the change in context — does this modification interact poorly with code outside the diff? A generic agent reviews only what it sees. (3) Distinguish blocking issues from suggestions — not all feedback is equally important. Without this judgment, the review buries critical issues among style nits. (4) Consider testability — does this change make the code harder to test? A generic agent may approve code that works but is untestable. (5) Assess naming and abstraction quality — are the names and boundaries chosen ones that will make sense to the next developer? A generic agent checks syntax, not whether the code communicates its intent clearly."},{id:"ds-2",difficulty:"intermediate",question:"Design the structure of a debugging domain skill. What phases should it include, what should the skill do in each phase, and how should it handle the case where the first hypothesis is wrong?",hint:"Think about the systematic debugging process: reproduce, hypothesize, test, conclude.",solution:"Phases: (1) Reproduce — the skill first confirms it can observe the reported failure. If it cannot reproduce, it stops and reports this rather than guessing. (2) Gather context — collect error messages, recent changes, relevant logs, and system state. (3) Hypothesize — based on context, generate ranked hypotheses (most likely cause first). (4) Test — for each hypothesis starting with the most likely, identify a specific check that would confirm or refute it. Execute the check. (5) Iterate — if the hypothesis is refuted, move to the next one. If all initial hypotheses fail, broaden the investigation scope and generate new hypotheses. (6) Conclude — when a hypothesis is confirmed, document the root cause, the evidence, and a recommended fix. The key design choice is making the skill iterative — it must not commit to its first guess but systematically work through possibilities."},{id:"ds-3",difficulty:"advanced",question:'A team wants to build a refactoring domain skill. The challenge is that "good refactoring" is highly context-dependent — what improves one codebase may harm another. How do you design a refactoring skill that adapts to different codebase conventions without requiring a separate skill for each project?',hint:"Think about how the skill can learn the conventions of a codebase from the codebase itself.",solution:'Design a two-phase refactoring skill. Phase 1 (Convention Discovery): before suggesting any changes, the skill examines the existing codebase to infer conventions — naming patterns, module structure, abstraction style, test organization, and comment density. It builds a "convention profile" from what it observes. Phase 2 (Convention-Aligned Refactoring): the skill applies refactoring improvements that align with the discovered conventions rather than imposing external standards. For example, if the codebase uses long descriptive function names, the skill does not introduce short abbreviated ones. The convention profile is parameterizable — teams can override inferred conventions where the codebase is inconsistent and they want to converge on a specific style. This approach adapts to any project without project-specific skill variants because the conventions come from the code, not the skill definition.'}]})]})}const z=Object.freeze(Object.defineProperty({__proto__:null,default:m},Symbol.toStringTag,{value:"Module"}));function f(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Scheduled Agents"}),e.jsx("p",{children:"Not every agent task is triggered by a human in the moment. Some tasks need to happen regularly — every morning, every hour, every Monday. Scheduled agents run on a timer, executing recurring workflows without requiring someone to remember to start them. They are the heartbeat of an automated development practice."}),e.jsx(t,{title:"Scheduled Agent",number:"10.9",children:e.jsx("p",{children:"A scheduled agent is an agent configured to execute a specific skill or workflow at predetermined intervals. The schedule is typically defined using cron-style expressions that specify when the agent runs. Scheduled agents operate without human initiation — they wake up, perform their task, report results, and go dormant until the next scheduled run. They are ideal for tasks that must happen consistently regardless of whether anyone remembers to trigger them."})}),e.jsx(s,{title:"The Night Security Guard",children:e.jsx("p",{children:"A night security guard walks the same patrol route at regular intervals — not because something has gone wrong, but because consistent monitoring prevents problems from growing undetected. A scheduled agent serves the same function: it patrols the codebase, the infrastructure, or the project status at regular intervals, catching issues early before they compound into crises."})}),e.jsx("p",{children:"The power of scheduled agents lies in consistency. Humans are unreliable at recurring tasks — they forget, they get busy, they skip a week. Scheduled agents never forget. But this reliability creates its own risks: a misconfigured scheduled agent produces incorrect results just as reliably as a correct one produces good results. The damage from a bad scheduled agent compounds over time."}),e.jsx(n,{title:"Scheduled Agents Need Monitoring, Not Just Scheduling",number:"10.7",children:e.jsx("p",{children:"Setting up a schedule is the easy part. The hard part is ensuring the scheduled agent continues to produce correct, useful results over time. Every scheduled agent needs a monitoring layer that tracks: did it run? Did it succeed? Were the results consistent with expectations? Did it take an unusual amount of time? An unmonitored scheduled agent is an assumption that everything is fine — and assumptions degrade."})}),e.jsx(o,{title:"Schedule creep wastes resources silently",children:e.jsx("p",{children:"Teams tend to add scheduled agents but rarely remove them. Over months, the schedule fills with agents running tasks that are no longer relevant — checking deprecated services, generating reports nobody reads, scanning repositories that have been archived. Periodically audit scheduled agents and remove those that no longer serve a purpose. Every scheduled agent should have an owner and a justification for continued operation."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"sa-1",difficulty:"beginner",question:"A team wants a scheduled agent that checks for outdated dependencies every Monday morning. What information should the agent report, and who should receive the report?",hint:"Think about what makes a dependency report actionable versus just noisy.",solution:"The agent should report: (1) dependencies with available updates, categorized by severity (security patches vs. minor updates vs. major version changes), (2) how far behind each dependency is (one version vs. twenty), (3) whether any outdated dependency has known security vulnerabilities. The report should go to the team's primary communication channel and specifically mention the team member responsible for dependency maintenance. A report that lists every available update equally is noisy; a report that highlights security-critical updates and ranks others by staleness is actionable. The Monday timing gives the team a full work week to address issues."},{id:"sa-2",difficulty:"intermediate",question:"A scheduled agent runs every hour to check system health. One night, the system it monitors goes down, and the agent generates 8 consecutive failure alerts before anyone responds. How should the scheduling system handle repeated identical failures?",hint:"Think about alert fatigue and escalation strategies.",solution:'The scheduling system should implement alert deduplication and escalation. (1) First failure: send a standard alert to the on-call channel. (2) Second consecutive identical failure: mark the alert as "persistent" and escalate to the on-call individual directly. (3) Third and subsequent: suppress duplicate alerts but maintain a running counter. Send a single summary every N failures (e.g., "System health check has failed 8 consecutive times since 11 PM — issue remains unresolved"). (4) When the check finally succeeds: send a recovery notification with the total downtime duration. This prevents alert fatigue while ensuring the issue is escalated appropriately. The key principle is that repeated identical alerts carry no new information — escalation and summarization carry the signal without the noise.'}]})]})}const C=Object.freeze(Object.defineProperty({__proto__:null,default:f},Symbol.toStringTag,{value:"Module"}));function g(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Event-Driven Agents"}),e.jsx("p",{children:"Scheduled agents run on a clock. Event-driven agents run on signals. They sit idle until something happens — a pull request is opened, a deployment completes, a test fails, an issue is filed — and then they spring into action. Event-driven agents are reactive by design: they respond to the world rather than polling it."}),e.jsx(t,{title:"Event-Driven Agent",number:"10.10",children:e.jsx("p",{children:"An event-driven agent is an agent that activates in response to an external event rather than a schedule or direct invocation. Events come from many sources: version control systems (push, merge, branch creation), CI pipelines (build success, test failure), project management tools (issue creation, status change), or infrastructure monitors (resource alerts, uptime changes). The agent subscribes to specific event types and executes a corresponding skill when those events occur."})}),e.jsx(s,{title:"The Smoke Detector",children:e.jsx("p",{children:"A smoke detector does not check for fires on a schedule. It monitors continuously and activates only when smoke is present. This is far more efficient than a guard walking through every room every hour, and far more responsive — the alarm sounds within seconds of detection, not at the next scheduled patrol. Event-driven agents follow this model: they respond in the moment that action is needed, not at the next convenient time."})}),e.jsx("p",{children:"The key advantage of event-driven agents over scheduled ones is timeliness. A scheduled agent that checks for new pull requests every hour might wait up to 59 minutes before reviewing a PR. An event-driven agent triggered by the PR creation event starts reviewing within seconds. For workflows where speed matters, event-driven is the superior pattern."}),e.jsx(n,{title:"Filter Events Before Processing Them",number:"10.8",children:e.jsx("p",{children:"Not every event of a subscribed type warrants agent action. A PR-opened event for a documentation-only change may not need the full security review agent. Build filtering logic between the event source and the agent: check the event payload, evaluate whether the agent's skill is relevant, and skip execution when it is not. An agent that triggers on every event regardless of relevance wastes resources and generates noise."})}),e.jsx(a,{title:"Idempotency is essential for event-driven agents",type:"tip",children:e.jsx("p",{children:"Events can be delivered more than once — network retries, duplicate webhooks, and system replays are common. An event-driven agent must produce the same result whether it processes an event once or three times. If the agent creates a review comment, it should check whether it already commented before posting a duplicate. Designing for idempotency prevents event-driven agents from creating confusing duplicate outputs."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ed-1",difficulty:"beginner",question:"A team wants an agent that automatically labels new issues based on their content. Should this be scheduled (check for new issues every 10 minutes) or event-driven (trigger when an issue is created)? Justify your choice.",hint:"Consider response time expectations and resource efficiency.",solution:"Event-driven is the better choice. Reasons: (1) Timeliness — users expect labels to appear quickly after filing an issue, not up to 10 minutes later. (2) Efficiency — a scheduled agent runs every 10 minutes even when no issues are filed, wasting resources. An event-driven agent runs only when there is work to do. (3) Simplicity — an event-driven agent processes one issue at a time as it arrives. A scheduled agent must track which issues it has already processed to avoid re-labeling. The only scenario where scheduled might be preferable is if the event infrastructure is unreliable and events are sometimes dropped — then periodic polling serves as a safety net."},{id:"ed-2",difficulty:"intermediate",question:'An event-driven agent responds to "deployment completed" events by running a smoke test suite. During a busy deployment day, 12 deployments happen in rapid succession. What problems might arise, and how should the system handle them?',hint:"Think about resource contention, ordering, and whether all 12 smoke test runs are necessary.",solution:"Problems: (1) Resource contention — 12 simultaneous smoke test runs may overwhelm the test infrastructure or the target environment. (2) Obsolescence — if deployment 12 replaces deployment 11, smoke-testing deployment 11 is pointless by the time it completes. (3) Interference — smoke tests running against deployment 7 may see inconsistent behavior if deployment 8 is applied mid-test. Solutions: (a) Queue events and process them serially rather than in parallel. (b) Implement event coalescing — if a new deployment event arrives while a smoke test is pending, cancel the pending test and test only the latest deployment. (c) Add a brief debounce window — wait 2 minutes after a deployment event before starting smoke tests, canceling if a newer deployment arrives in that window. The goal is to test the state that matters (the latest deployment) rather than every intermediate state."},{id:"ed-3",difficulty:"advanced",question:"Design an event routing system where different types of events trigger different agent skills, and some events trigger multiple skills in a defined order. What are the components of this system and how do they interact?",hint:"Think about event buses, subscription registries, and orchestration layers.",solution:"Components: (1) Event ingestion layer — receives raw events from external sources (webhooks, message queues), normalizes them into a standard event format with type, payload, source, and timestamp. (2) Subscription registry — maps event types to skills, with optional filter predicates. One event type can map to multiple skills. Each mapping specifies execution order (priority number) and whether the skill is required or optional. (3) Event router — when an event arrives, the router looks up all matching subscriptions, orders them by priority, evaluates filter predicates against the event payload, and produces an execution plan. (4) Execution orchestrator — runs the execution plan, passing results from earlier skills to later ones when configured as a chain. Handles failures according to the subscription's failure policy (stop chain, skip and continue, or retry). (5) Event log — records every event, every routing decision, and every execution result for auditability. The key design choice is separating routing (which skills to run) from orchestration (how to run them) — this lets either layer change independently."}]})]})}const P=Object.freeze(Object.defineProperty({__proto__:null,default:g},Symbol.toStringTag,{value:"Module"}));function y(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Hook-Based Automation"}),e.jsx("p",{children:"Hooks are automation's surgical instrument. Rather than triggering an agent based on external events or schedules, hooks attach logic directly to specific moments in an agent's own lifecycle — before it reads a file, after it makes a tool call, before it submits a response. Hooks let you inject validation, logging, transformation, or guardrails at precise points in the workflow."}),e.jsx(t,{title:"Hook",number:"10.11",children:e.jsx("p",{children:"A hook is a callback that executes automatically at a defined point in an agent's action lifecycle. Pre-hooks run before an action and can modify, validate, or block it. Post-hooks run after an action and can log, transform, or react to its result. Hooks are transparent to the main workflow — the skill does not need to know that hooks exist. This separation means cross-cutting concerns like security checks, audit logging, and output formatting can be added without modifying the skills themselves."})}),e.jsx(s,{title:"Airport Security Checkpoints",children:e.jsx("p",{children:"When you board a flight, you pass through security between the terminal and the gate. The security checkpoint is a pre-hook — it inspects what is about to happen (you boarding the plane) and can block it if something is wrong. You do not arrange your own security screening; it happens automatically at a defined point in the process. Hooks work the same way: they intercept the flow at specific points, inspect or modify what is passing through, and either allow or block the action."})}),e.jsx("p",{children:"The most common uses for hooks in agent systems are: pre-action validation (is this tool call safe?), post-action logging (record what was done for audit), output transformation (format results before presenting them), and resource guarding (prevent actions that would exceed budgets or rate limits)."}),e.jsx(n,{title:"Hooks Must Be Fast and Invisible",number:"10.9",children:e.jsx("p",{children:"A hook that takes longer than the action it wraps defeats its purpose. Hooks should execute quickly and not disrupt the user's experience of the workflow. If a hook needs to perform substantial work — like running a full security analysis — it should do so asynchronously or in a limited, fast-path version. The user should experience hooks as guardrails, not as speed bumps."})}),e.jsx(o,{title:"Ordering conflicts between hooks",children:e.jsx("p",{children:"When multiple hooks attach to the same action point, their execution order matters. A logging hook that runs before a transformation hook records the untransformed output. A security hook that runs after a modification hook checks the modified version. If hook ordering is undefined or arbitrary, behavior becomes unpredictable. Always define explicit ordering for hooks that share an attachment point."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ha-1",difficulty:"beginner",question:"An agent can execute shell commands as part of its workflow. Design a pre-hook that prevents dangerous commands from executing. What should it check, and what should it do when it detects a dangerous command?",hint:"Think about what makes a shell command dangerous and how to categorize risk levels.",solution:'The pre-hook should: (1) Intercept every shell command before execution. (2) Check against a blocklist of dangerous patterns — commands that delete files recursively, modify system configuration, access sensitive directories, or make network requests to unknown hosts. (3) Categorize matches by severity: "blocked" (never allowed, e.g., rm -rf /), "requires confirmation" (potentially dangerous, e.g., git push --force), and "allowed" (safe operations). (4) For blocked commands: halt execution, log the attempt, and return an error explaining why. (5) For confirmation-required commands: pause and request explicit approval before proceeding. The hook should never silently allow a dangerous command and should never silently block a safe one — both false positives and false negatives erode trust.'},{id:"ha-2",difficulty:"intermediate",question:"A team wants to add audit logging to every tool call an agent makes, without modifying any existing skills. Design a post-hook system that captures what was called, what inputs were provided, and what result was returned. What should the log entry include?",hint:"Think about what information you would need to reconstruct exactly what happened during a session.",solution:"The post-hook attaches to every tool invocation's completion point. Each log entry should include: (1) timestamp, (2) session ID (to group entries from one workflow run), (3) agent identity (which agent in a multi-agent system), (4) tool name, (5) sanitized input parameters (with sensitive values like passwords redacted), (6) result summary (success/failure plus a truncated result for large outputs), (7) execution duration, (8) the skill that initiated the tool call. The log should be written to an append-only store that the agent cannot modify or delete. Sanitization is critical — the audit log must be useful for investigation without becoming a security liability by storing credentials or personal data in plaintext."},{id:"ha-3",difficulty:"advanced",question:"Design a hook that enforces a token budget across an entire multi-step workflow. The hook must track cumulative usage, warn when approaching the limit, and halt execution when the budget is exhausted. How does it handle the case where the final step is critical and must not be skipped?",hint:"Think about budget reservation — setting aside tokens for must-run final steps.",solution:'Design: (1) A pre-hook on every language model call that checks cumulative tokens against the budget. (2) The budget is partitioned: a "reserved" portion for critical final steps and an "available" portion for everything else. For example, if the budget is 100K tokens and the final summarization step typically uses 10K, reserve 10K and allow the other steps to use up to 90K. (3) Warning threshold: when available budget drops below 20%, the hook injects a system message advising the agent to be more concise and prioritize essential work. (4) Soft limit: when available budget is exhausted, non-critical steps are skipped with a log entry explaining why. (5) Hard limit: the reserved budget is released only for the designated critical final step. If even the reserved budget is insufficient, the hook allows the step to proceed but truncates input to fit. The key insight is that a flat budget with a hard cutoff risks stopping right before the most important step. Budget reservation ensures critical work always executes.'}]})]})}const _=Object.freeze(Object.defineProperty({__proto__:null,default:y},Symbol.toStringTag,{value:"Module"}));function w(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Agents in Continuous Integration"}),e.jsx("p",{children:"Continuous integration pipelines are where code changes meet quality gates. Traditionally these gates are static: run tests, check linting, measure coverage. Agents add a dynamic, intelligent layer — they can review changes contextually, triage failures, suggest fixes, and make nuanced decisions that static checks cannot. Integrating agents into CI transforms pipelines from pass/fail gatekeepers into collaborative participants in the development process."}),e.jsx(t,{title:"CI Agent",number:"10.12",children:e.jsx("p",{children:'A CI agent is an agent that participates in a continuous integration pipeline as a first-class step. Unlike static checks that apply fixed rules, a CI agent can interpret context: it understands what the change intends to accomplish, evaluates whether the implementation achieves that intent, and provides feedback that goes beyond "pass" or "fail." CI agents operate within the constraints of the pipeline — they must complete within time limits, produce structured output that the pipeline can act on, and handle failures gracefully.'})}),e.jsx(s,{title:"The Building Inspector vs. The Architect",children:e.jsx("p",{children:"A traditional CI check is like a building inspector with a checklist: does this meet code? Is the wiring correct? Pass or fail. A CI agent is more like having the architect visit the construction site — they check the code requirements too, but they also assess whether the design intent is being realized, whether the construction approach will cause problems later, and whether there is a better way to achieve the same goal. Both are valuable; the agent adds the layer of judgment that checklists cannot capture."})}),e.jsx("p",{children:"The critical constraint for CI agents is that they operate in a pipeline with strict expectations about time, output format, and reliability. A CI step that sometimes takes five minutes and sometimes takes fifty minutes makes the pipeline unpredictable. A CI agent that produces brilliant analysis but in a format the pipeline cannot parse is useless to automation."}),e.jsx(n,{title:"CI Agents Must Be Deterministic in Behavior, Not Just Output",number:"10.10",children:e.jsx("p",{children:"A CI agent's output may vary — different changes warrant different feedback. But its behavior must be predictable: it always completes within a time bound, always produces structured output in the expected format, always exits with a meaningful status code, and never silently fails. Developers build trust with CI agents by experiencing consistent behavior, even when the content of feedback varies."})}),e.jsx(a,{title:"Start with advisory, not blocking",type:"tip",children:e.jsx("p",{children:"When introducing a CI agent, configure it as advisory — it posts comments and suggestions but does not block the pipeline. This lets the team calibrate the agent's judgment before giving it veto power. Only promote a CI agent to a blocking check after the team has verified that its assessments are consistently trustworthy and its false positive rate is acceptably low."})}),e.jsx(o,{title:"Flaky agents destroy pipeline trust",children:e.jsx("p",{children:"If a CI agent intermittently fails due to timeouts, rate limits, or nondeterministic behavior, developers will learn to ignore it — or worse, to re-run the pipeline until it passes. A flaky agent is worse than no agent because it trains the team to distrust automated feedback. If an agent cannot be made reliable, remove it from the pipeline until it can."})}),e.jsx(i,{title:"Exercises",exercises:[{id:"ci-1",difficulty:"beginner",question:"A team adds a CI agent that reviews every pull request for potential issues. In the first week, it flags 40 issues across 10 PRs, but only 12 are genuine problems — the rest are false positives. What is the impact on the team, and what should they do?",hint:"Think about how developers respond to tools that are wrong most of the time.",solution:`With a 70% false positive rate, developers will quickly learn to dismiss the agent's feedback without reading it — even the 30% that are genuine problems. This is the "cry wolf" effect. The team should: (1) Immediately switch the agent from blocking to advisory mode if it was blocking. (2) Analyze the 28 false positives to identify patterns — are they concentrated in certain types of changes or certain rule categories? (3) Disable the rules or heuristics responsible for the most false positives. (4) Re-launch with a narrower scope that has a much higher precision rate — it is better to catch fewer real issues with high confidence than to catch more issues with low confidence. (5) Gradually expand scope as precision is validated. The target should be at least 80% precision before the agent's feedback is taken seriously.`},{id:"ci-2",difficulty:"intermediate",question:"Design the output format for a CI agent that reviews pull requests. The output must be useful to both humans (who read PR comments) and machines (the CI pipeline that decides pass/fail). What structure achieves both goals?",hint:"Think about structured data that can be rendered as human-readable comments and also parsed programmatically.",solution:'Use a structured format with two rendering paths. The data structure includes: (1) overall_status: "pass", "warn", or "fail", (2) findings: an array where each entry has severity (critical/warning/info), category (security/performance/correctness/style), location (file path and line range), description (human-readable explanation), and confidence (high/medium/low). For the machine path: the pipeline reads overall_status to decide pass/fail, and can filter findings by severity to determine whether to block. For the human path: a renderer converts findings into formatted PR comments grouped by file, with severity indicators and inline annotations. The same data serves both audiences. Key design choice: include confidence levels so the pipeline can be configured to block only on high-confidence critical findings, reducing false-positive blocks while still surfacing lower-confidence observations as non-blocking comments.'},{id:"ci-3",difficulty:"advanced",question:"A CI agent must complete its review within a 5-minute time limit to avoid slowing the pipeline. For small PRs this is easy, but large PRs (hundreds of changed files) cannot be fully analyzed in time. Design a strategy for handling time-constrained analysis of variable-size inputs.",hint:"Think about prioritization, progressive analysis, and graceful degradation.",solution:'Use a tiered analysis strategy. (1) Triage phase (30 seconds): quickly scan all changed files and classify them by risk — files touching authentication, database access, or public APIs are high-risk; style-only changes and documentation are low-risk. (2) Deep analysis phase (3.5 minutes): analyze files in risk order, starting with the highest-risk files. Track elapsed time continuously. (3) Time check at each file: before starting analysis of the next file, check remaining time. If insufficient time remains for another deep analysis, switch to shallow mode. (4) Shallow analysis (remaining time): for unanalyzed files, perform only fast checks (pattern matching for known dangerous patterns, surface-level structure review). (5) Report phase (1 minute reserved): compile results, clearly marking which files received deep analysis versus shallow analysis. Include a note: "12 of 47 files received detailed analysis; 35 received surface-level review due to time constraints." This ensures the most important files always get thorough review, the pipeline time limit is always respected, and the team knows exactly what was and was not analyzed.'}]})]})}const D=Object.freeze(Object.defineProperty({__proto__:null,default:w},Symbol.toStringTag,{value:"Module"}));export{x as a,j as b,T as c,q as d,A as e,S as f,I as g,z as h,C as i,P as j,_ as k,D as l,v as s};
